   181→  static address return_entry(TosState state, int length, Bytecodes::Code code);
   182→
   183→  // Safepoint support
   184→  static void       notice_safepoints();                        // stops the thread when reaching a safepoint
   185→  static void       ignore_safepoints();                        // ignores safepoints
   186→
   187→  // Deoptimization support
   188→  // Compute the entry address for continuation after
   189→  static address deopt_continue_after_entry(Method* method,
   190→                                            address bcp,
   191→                                            int callee_parameters,
   192→                                            bool is_top_frame);
   193→  // Deoptimization should reexecute this bytecode
